          <Btn sm v="ghost" onClick={()=>exportExcel(
            `Discipline_${avecEns?"College":"Primaire"}`,
            ["Élève","Classe","Type","Date","Motif","Justifié"],
            absences.map(a=>[a.eleveNom,a.classe,a.type,a.date,a.motif||"",a.justifie])
          )}>📥 Export Excel</Btn>
